const items = $input.all();
const total = items.length;
let spam = 0;
let notSpam = 0;
let unknown = 0;
let memoryUsed = 0;

const samples = items.slice(0, 5).map((item, i) => {
  const output = item?.json?.output;
  const asText = typeof output === 'string' ? output : JSON.stringify(output ?? {});
  const text = String(asText).trim();
  const verdict = typeof output === 'object'
    ? String(output?.verdict ?? '').toUpperCase()
    : (text.match(/\b(SPAM|NOT_SPAM)\b/i)?.[1] || '').toUpperCase();

  if (verdict === 'SPAM') spam += 1;
  else if (verdict === 'NOT_SPAM') notSpam += 1;
  else unknown += 1;

  const usedMemory = typeof output === 'object'
    ? Boolean(output?.memory_used)
    : /qdrant|memory/i.test(text);
  if (usedMemory) memoryUsed += 1;

  return { index: i, verdict: verdict || 'UNKNOWN', usedMemory, preview: text.slice(0, 240) };
});

return [{
  json: {
    total,
    spam,
    notSpam,
    unknown,
    memoryUsed,
    samples
  }
}];

const source = $json ?? {};
const output = $json?.output;
const raw = typeof output === "string" ? output : JSON.stringify(output ?? {});

let verdict = "";
let reason = "";
let modelMemoryUsed = false;

if (output && typeof output === "object") {
  verdict = String(output.verdict ?? "").toUpperCase();
  reason = String(output.reason ?? "").trim();
  modelMemoryUsed = Boolean(output.memory_used);
} else {
  const text = String(raw).trim();
  const match = text.match(/\b(SPAM|NOT_SPAM)\b\s*[:|-]?\s*(.*)$/i);
  if (match) {
    verdict = match[1].toUpperCase();
    reason = String(match[2] ?? "").trim();
  }
  modelMemoryUsed = /qdrant|memory/i.test(text);
}

if (verdict !== "SPAM") {
  return [];
}

const memoryText = [
  `from: ${source.From ?? source.from ?? ""}`,
  `subject: ${source.Subject ?? source.subject ?? ""}`,
  `snippet: ${source.snippet ?? ""}`,
  `verdict: ${verdict}`,
  `reason: ${reason || "none"}`,
  `labels: ${JSON.stringify(source.labels ?? [])}`
].join("\n");

return {
  json: {
    memoryText,
    messageId: source.id ?? "",
    verdict,
    reason,
    modelMemoryUsed,
    sourceFrom: source.From ?? source.from ?? "",
    sourceSubject: source.Subject ?? source.subject ?? "",
    sourceLabels: source.labels ?? []
  }
};

